int firstOccurence(const int arr[], int n, int target){
    int left = 0, right = n;
    while(right-left>1){
        int middle = (right + left)/2;
        if(arr[middle]>=target) right = middle;
        else left = middle;
    }
    return right;
}
int lastOccurence(const int arr[], int n, int target){
    int left = 0, right = n;
    while(right-left>1){
        int middle = (right + left)/2;
        if(arr[middle]>target) right = middle;
        else left = middle;
    }
    return left;
}
