function firstOccurrence(arr, n, target) {
    let left = 0, right = n - 1;
    while (left <= right) {
        let middle = Math.floor((right + left) / 2);
        if (arr[middle] >= target) right = middle - 1;
        else left = middle + 1;
    }
    return left;
}

function lastOccurrence(arr, n, target) {
    let left = 0, right = n - 1;
    while (left <= right) {
        let middle = Math.floor((right + left) / 2);
        if (arr[middle] > target) right = middle - 1;
        else left = middle + 1;
    }
    return right;
}

function countOccurrences(arr, n, target) {
    let first = firstOccurrence(arr, n, target);
    let last = lastOccurrence(arr, n, target);
    if (first <= last && arr[first] == target && arr[last] == target) {
        return last - first + 1;
    }
    return 0;
}
